Here's a C++ implementation for differentiating polynomials:

```cpp
#include <iostream>
#include <vector>
#include <cassert>

// Structure to represent a polynomial
struct Polynomial {
    std::vector<int> coefficients; // Coefficients from highest degree to lowest

    // Constructor to initialize the polynomial
    Polynomial(const std::vector<int>& coeffs) : coefficients(coeffs) {}

    // Function to get the degree of the polynomial
    int degree() const {
        return coefficients.size() - 1;
    }

    // Function to differentiate the polynomial
    Polynomial differentiate() const {
        if (degree() <= 0) {
            // If the polynomial is constant (degree 0), its derivative is 0
            return Polynomial({0});
        }

        // Create a new polynomial for the derivative
        Polynomial derivative(degree());
        for (int i = 1; i <= degree(); ++i) {
            derivative.coefficients[i-1] = i * coefficients[i];
        }
        return derivative;
    }

    // Function to print the polynomial
    void print() const {
        std::cout << "Polynomial: ";
        for (int i = degree(); i >= 0; --i) {
            if (i == 0) {
                std::cout << coefficients[i];
            } else if (i == 1) {
                std::cout << coefficients[i] << "x + ";
            } else {
                std::cout << coefficients[i] << "x^" << i << " + ";
            }
        }
        std::cout << std::endl;
    }
};

int main() {
    // Example polynomial: 3x^2 + 2x + 1
    std::vector<int> coeffs = {3, 2, 1};
    Polynomial p(coeffs);

    std::cout << "Original Polynomial: ";
    p.print();

    Polynomial dp = p.differentiate();
    std::cout << "Differentiated Polynomial: ";
    dp.print();

    return 0;
}
